( function ( $ ) {
    'use strict';

    $( document ).on( 'click', '.ovic-field .delete-transients', function ( e ) {
        e.preventDefault();

        var $this    = $( this ),
            $text    = $this.data( 'text-done' ),
            $success = $this.parent().find( '.ovic-text-success' ),
            $spinner = $this.parent().find( '.spinner' );
        $spinner.addClass( 'is-active' );
        $.post(
            ajaxurl,
            {
                action   : 'tuongnam_delete_transients',
                security : tuongnam_admin_params.security
            },
            function ( response ) {
                $spinner.removeClass( 'is-active' );
                $success.html( $text.replace( '%n', response ) );
            }
        );
    } );

    $( document ).on( 'paste', 'input[name="_custom_metabox_post_options[google_doc]"]', function ( event ) {
        const $this = $( this );
        setTimeout( function () {
            if ( $this.val() ) {
                const text = $this.val().split( '/d/' );
                if ( text[ 1 ] ) {
                    $this.val( text[ 0 ] + '/d/' + text[ 1 ].split( '/' )[ 0 ] + '/preview' )
                }
            }
        }, 0 );
    } );

} )( window.jQuery );